#include<stdio.h>
long long int prime(long long int x)
{
	if (x < 2)
		return 0;
	if (x % 2 == 0)
		return 2;
	long long int i;
	for (i = 3; i * i <= x; i++)
		if (x % i == 0)
			return i;
	return x;
}
long long int modpow(long long int a, long long int n, long long int p)
{
	if (n < 0)return 0;
	long long int res = 1;
	while (n > 0)
	{
		if (n % 2 == 1)
			res = res * a % p;
		n /= 2;
		a = a * a % p;
	}
	return res;
}
int main()
{
	long long int x, n;
	scanf("%lld %lld", &x, &n);
	long long int ans = 1, p = 1000000007;
	long long int q, v;
	while (x > 1)
	{
		q = prime(x);
		while (x % q == 0)
			x /= q;
		v = q;
		while (n / v > 0)
		{
			ans = ans * modpow(q, n / v, p) % p;
			if (n / v < q)break;
			v *= q;
		}
	}
	printf("%lld\n", ans);
	return 0;
}

