pub struct Scanner {
  buffer: Vec<String>
}

impl Scanner {
  pub fn new() -> Scanner {
    Scanner { buffer: Vec::new() }
  }

  pub fn next<T: std::str::FromStr>(&mut self) -> T {
    loop {
      if let Some(token) = self.buffer.pop() {
          return token.parse().ok().expect("Failed parse");
      }
      let mut input = String::new();
      std::io::stdin().read_line(&mut input).expect("Failed read");
      self.buffer = input.split_whitespace().rev().map(String::from).collect();
    }
  }
}

fn calculate_divs(mut x: u32) -> Vec<u32> {
  let mut divs: Vec<u32> = Vec::new();
    for p in 2..100_000 {
    if x % p == 0 {
      divs.push(p);
      while x % p == 0 {
        x /= p;
      }
    }
  }
  if x > 1 {
    divs.push(x);
  }
  return divs;
}

const MOD: u64 = 1_000_000_007;

fn bin_pow(mut a: u64, mut n: u64) -> u64 {
  let mut x: u64 = 1;
  while n > 0 {
    if (n & 1) == 1 {
      x = x * a % MOD;
    }
    a = a * a % MOD;
    n >>= 1;
  }
  return x;
}

fn main() {
  let mut scan = Scanner::new();
  let x: u32 = scan.next();
  let n: u64 = scan.next();
  let divs: Vec<u32> = calculate_divs(x);

  let mut ans: u64 = 1;
  for &d in divs.iter() {
    let mut copy_n: u64 = n;
    let mut power: u64 = 0;
    loop {
      copy_n /= d as u64;
      if copy_n == 0 {
        break;
      }
      power += copy_n;
    }
    ans = ans * bin_pow(d as u64, power) % MOD;
  }
  println!("{}", ans);
}
